 export const HookForm = ({
 	mode,
 	initialData,
 	onSubmit,
 	onCancel,
 }: HookFormProps) => {
 	const [formData, setFormData] = useState<FormData>(() => {
 		if (mode === "edit" && initialData) {
 			return {
 				name: initialData.name,
 				enabled: initialData.enabled,
