				</Button>
				<Button disabled={isSubmitting} type="submit">
					{(() => {
						if (isSubmitting) {
							return "Saving...";
						}
						if (mode === "create") {
							return "Create Hook";
						}
						return "Save Changes";
					})()}
				</Button>
			</div>
		</form>
	);
};

