cat << 'EOF' > ui/src/features/hooks-view/components/trigger-action-selector.tsx
import { VSCodeCheckbox } from "@/components/ui/vscode-checkbox";
import { VSCodeSelect } from "@/components/ui/vscode-select";
import { AgentDropdown } from "@/components/hooks/agent-dropdown";
import { AgentTypeSelector } from "./agent-type-selector";
import { AcpAgentForm } from "./acp-agent-form";
import { AcpKnownAgentsPanel } from "./acp-known-agents-panel";
import { GitActionForm } from "./git-action-form";
import { GitHubActionForm } from "./github-action-form";
import type {
	ACPActionParams,
	ACPAgentDescriptor,
	ActionConfig,
	ActionType,
	AgentActionParams,
	AgentType,
	CustomActionParams,
	GitActionParams,
	GitHubActionParams,
	KnownAgentStatus,
	MCPActionParams,
	OperationType,
	SelectedMCPTool,
	TriggerCondition,
    EventSource,
    Condition,
    Schedule,
} from "../types";
import type { ChangeEvent } from "react";
import { useMCPServers } from "../hooks/use-mcp-servers";
import { useAcpAgents } from "../hooks/use-acp-agents";
import { useKnownAcpAgents } from "../hooks/use-known-acp-agents";
import { MCPToolsSelector } from "./mcp-tools-selector";
import { ArgumentTemplateEditor } from "./argument-template-editor";
import { CopilotCliOptionsPanel } from "./cli-options/copilot-cli-options-panel";

interface TriggerActionSelectorProps {
	events: EventSource[];
	conditions: Condition[];
	schedule: Schedule;
	action: ActionConfig;
	disabled?: boolean;
	actionError?: string;
	onEventsChange: (events: EventSource[]) => void;
	onConditionsChange: (conditions: Condition[]) => void;
	onScheduleChange: (schedule: Schedule) => void;
	onActionChange: (action: ActionConfig) => void;
	onClearActionError?: () => void;
}

const getDefaultParameters = (type: ActionType): ActionConfig["parameters"] => {
	switch (type) {
		case "git":
			return {
				operation: "commit",
				messageTemplate: "",
				pushToRemote: false,
			} as GitActionParams;
		case "github":
			return {
				operation: "open-issue",
			} as GitHubActionParams;
		case "custom":
			return {
				agentName: "",
				prompt: "",
				selectedTools: [],
			} as CustomActionParams;
		case "mcp":
			return {
				prompt: "",
				selectedTools: [],
				// Legacy fields for backward compatibility
				serverId: "",
				serverName: "",
				toolName: "",
				toolDisplayName: "",
			} as MCPActionParams;
		case "acp":
			return {
				mode: "local",
				agentCommand: "",
				taskInstruction: "",
			} as ACPActionParams;
		default:
			return {
				command: "",
			} as AgentActionParams;
	}
};

const SPECKIT_OPERATIONS: Array<{ value: OperationType; label: string }> = [
	{ value: "research", label: "Research" },
	{ value: "datamodel", label: "Data Model" },
	{ value: "design", label: "Design" },
	{ value: "specify", label: "Specify" },
	{ value: "clarify", label: "Clarify" },
	{ value: "plan", label: "Plan" },
	{ value: "tasks", label: "Tasks" },
	{ value: "taskstoissues", label: "Tasks to Issues" },
	{ value: "analyze", label: "Analyze" },
	{ value: "checklist", label: "Checklist" },
	{ value: "constitution", label: "Constitution" },
	{ value: "implementation", label: "Implementation" },
	{ value: "unit-test", label: "Unit Tests" },
	{ value: "integration-test", label: "Integration Tests" },
];

export const TriggerActionSelector = ({
	events,
	conditions,
	schedule,
	action,
	disabled,
	actionError,
	onEventsChange,
	onConditionsChange,
	onScheduleChange,
	onActionChange,
	onClearActionError,
}: TriggerActionSelectorProps) => {
	// We'll just edit the first event for simplicity in this redesign
	const event = events[0] || { type: "agent-operation", agent: "speckit", operation: "specify", timing: "after" };

	// MCP servers state
	const { servers, loading: mcpLoading, error: mcpError } = useMCPServers();
	// ACP workspace-discovered agents
	const discoveredAgents = useAcpAgents();
	// ACP known-agent checklist state
	const { agents: knownAgents, toggle: toggleKnownAgent } = useKnownAcpAgents();

	const handleEventTypeChange = (e: ChangeEvent<HTMLSelectElement>) => {
		onEventsChange([{ ...event, type: e.target.value as any }]);
	};

	const handleTriggerAgentChange = (e: ChangeEvent<HTMLSelectElement>) => {
		onEventsChange([{ ...event, agent: e.target.value as AgentType }]);
	};

	const handleTriggerOperationChange = (e: ChangeEvent<HTMLSelectElement>) => {
		onEventsChange([{ ...event, operation: e.target.value as OperationType }]);
	};

	const handleTriggerTimingChange = (e: ChangeEvent<HTMLSelectElement>) => {
		onEventsChange([{ ...event, timing: e.target.value as "before" | "after" }]);
	};

	const handleWaitForCompletionChange = (e: ChangeEvent<HTMLInputElement>) => {
		onEventsChange([{ ...event, waitForCompletion: e.target.checked }]);
	};

	const handleScheduleTypeChange = (e: ChangeEvent<HTMLSelectElement>) => {
		onScheduleChange({ ...schedule, type: e.target.value as any });
	};

	const handleActionTypeChange = (e: ChangeEvent<HTMLSelectElement>) => {
		const newType = e.target.value as ActionType;
		onActionChange({
			type: newType,
			parameters: getDefaultParameters(newType),
		});
		onClearActionError?.();
	};

    const handleMCPToolsSelection = (selectedTools: SelectedMCPTool[]): void => {
		const params = action.parameters as MCPActionParams;
		onActionChange({
			...action,
			type: "mcp",
			parameters: {
				...params,
				selectedTools,
			} as MCPActionParams,
		});
		onClearActionError?.();
	};

	const renderActionParameters = () => {
		switch (action.type) {
			case "agent": {
				const params = action.parameters as AgentActionParams;
				return (
					<div className="flex flex-col gap-2">
						<div className="flex items-center gap-1">
							<label className="font-medium text-[color:var(--vscode-foreground)] text-sm">
								Command
							</label>
						</div>
						<ArgumentTemplateEditor
							disabled={disabled}
							error={actionError}
							onChange={(value) => {
								onActionChange({
									...action,
									parameters: { ...params, command: value },
								});
								onClearActionError?.();
							}}
							placeholder="/speckit.clarify --spec $specId"
							triggerType={event.operation}
							value={params.command || ""}
						/>
					</div>
				);
			}
			case "git": return <GitActionForm action={action} actionError={actionError} disabled={disabled} onActionChange={onActionChange} onClearActionError={onClearActionError} />;
			case "github": return <GitHubActionForm action={action} actionError={actionError} disabled={disabled} onActionChange={onActionChange} onClearActionError={onClearActionError} />;
			case "mcp": {
				const params = action.parameters as MCPActionParams;
				return (
					<div className="flex flex-col gap-4">
						<div className="flex flex-col gap-2">
							<label className="font-medium text-[color:var(--vscode-foreground)] text-xs">Instruction/Prompt</label>
							<textarea
								className="min-h-[80px] resize-y rounded border border-[color:var(--vscode-input-border)] bg-[color:var(--vscode-input-background)] px-3 py-2 text-[color:var(--vscode-input-foreground)] text-sm focus:border-[color:var(--vscode-focusBorder)] focus:outline-none"
								disabled={disabled}
								maxLength={1000}
								onChange={(e) => {
									onActionChange({ ...action, parameters: { ...params, prompt: e.target.value } as MCPActionParams });
									onClearActionError?.();
								}}
								value={params.prompt || ""}
							/>
						</div>
                        <div className="flex flex-col gap-2">
                            <MCPToolsSelector
                                disabled={disabled}
                                onSelectionChange={handleMCPToolsSelection}
                                selectedTools={params.selectedTools || []}
                                servers={servers}
                            />
                        </div>
					</div>
				);
			}
			default: return null;
		}
	};

	return (
		<div className="flex flex-col gap-4">
			<fieldset className="flex flex-col gap-3 rounded border border-[color:var(--vscode-panel-border)] p-3">
				<legend className="px-2 font-medium text-[color:var(--vscode-foreground)] text-sm">
					Event Source
				</legend>
                <div className="flex flex-col gap-3">
                    <VSCodeSelect disabled={disabled} label="Event Type" onChange={handleEventTypeChange} size="sm" value={event.type}>
                        <option value="agent-operation">Agent Operation</option>
                        <option value="execution-flow">Execution Flow</option>
                        <option value="repository">Repository Event</option>
                        <option value="manual">Manual Trigger</option>
                    </VSCodeSelect>

                    {event.type === 'agent-operation' && (
                        <>
                        <div className="flex gap-3">
                            <div className="flex-1">
                                <VSCodeSelect disabled={disabled} label="Agent" onChange={handleTriggerAgentChange} size="sm" value={event.agent}>
                                    <option value="speckit">SpecKit</option>
                                    <option value="openspec">OpenSpec</option>
                                </VSCodeSelect>
                            </div>
                            <div className="flex-1">
                                <VSCodeSelect disabled={disabled} label="Operation" onChange={handleTriggerOperationChange} size="sm" value={event.operation}>
                                    {SPECKIT_OPERATIONS.map((op) => (
                                        <option key={op.value} value={op.value}>{op.label}</option>
                                    ))}
                                </VSCodeSelect>
                            </div>
                        </div>
                        <div className="flex gap-3">
                            <div className="flex-1">
                                <VSCodeSelect disabled={disabled} label="Timing" onChange={handleTriggerTimingChange} size="sm" value={event.timing}>
                                    <option value="before">Before Operation</option>
                                    <option value="after">After Operation</option>
                                </VSCodeSelect>
                            </div>
                        </div>
                        {event.timing === "before" && (
                            <VSCodeCheckbox checked={event.waitForCompletion ?? false} disabled={disabled} onChange={handleWaitForCompletionChange}>
                                Wait for completion
                            </VSCodeCheckbox>
                        )}
                        </>
                    )}
                </div>
			</fieldset>

            <fieldset className="flex flex-col gap-3 rounded border border-[color:var(--vscode-panel-border)] p-3">
				<legend className="px-2 font-medium text-[color:var(--vscode-foreground)] text-sm">
					Schedule
				</legend>
                <VSCodeSelect disabled={disabled} label="Timing" onChange={handleScheduleTypeChange} size="sm" value={schedule.type || "immediate"}>
                    <option value="immediate">Immediate</option>
                    <option value="delayed">Delayed</option>
                    <option value="cron">Cron Schedule</option>
                </VSCodeSelect>
            </fieldset>

			<fieldset className="flex flex-col gap-3 rounded border border-[color:var(--vscode-panel-border)] p-3">
				<legend className="px-2 font-medium text-[color:var(--vscode-foreground)] text-sm">
					Action
				</legend>
				<VSCodeSelect disabled={disabled} label="Action Type" onChange={handleActionTypeChange} size="sm" value={action.type}>
					<option value="agent">Agent Command</option>
					<option value="git">Git Operation</option>
					<option value="github">GitHub Operation</option>
					<option value="mcp">Custom Tools</option>
					<option value="acp">ACP Agent</option>
				</VSCodeSelect>
				{renderActionParameters()}
				{actionError && <span className="text-[color:var(--vscode-errorForeground)] text-xs">{actionError}</span>}
			</fieldset>
		</div>
	);
};
EOF

